<script type="module">
/* ── 資訊彈窗互斥 ── */
window.hsnInfoToggle = function(panelId) {
    var btns = document.querySelectorAll('.info-btn');
    var panels = document.querySelectorAll('.info-panel');
    var target = document.getElementById('panel-' + panelId);
    var wasOn = target && target.classList.contains('on');
    btns.forEach(function(b) { b.classList.remove('on'); });
    panels.forEach(function(p) { p.classList.remove('on'); });
    if (!wasOn && target) {
        target.classList.add('on');
        var btn = document.querySelector('.info-btn[data-panel="' + panelId + '"]');
        if (btn) btn.classList.add('on');
    }
};

/* ── 線卡選擇 ── */
window.hsnSelectLine = function(line) {
    var cards = document.querySelectorAll('.line-card');
    var banners = document.querySelectorAll('.line-banner');
    var groups = document.querySelectorAll('.scene-group');
    cards.forEach(function(c) { c.classList.toggle('on', c.dataset.line === line); });
    banners.forEach(function(b) { b.classList.toggle('on', b.dataset.for === line); });
    groups.forEach(function(g) { g.classList.toggle('on', g.dataset.for === line); });
};

/* ── 場景手風琴互斥（同組只開一個） ── */
document.querySelectorAll('.scene').forEach(function(d) {
    d.addEventListener('toggle', function() {
        if (d.open) {
            var grp = d.dataset.group;
            document.querySelectorAll('.scene[data-group="' + grp + '"]').forEach(function(other) {
                if (other !== d && other.open) other.open = false;
            });
        }
    });
});

/* ── 跳轉 ── */
window.switchToOpening = async function(openingId) {
    function findApi(name) {
        var scopes = [window];
        try { if (window.parent && window.parent !== window) scopes.push(window.parent); } catch (e) {}
        try { if (window.top && window.top !== window && window.top !== window.parent) scopes.push(window.top); } catch (e) {}
        for (var i = 0; i < scopes.length; i++) {
            try { if (typeof scopes[i][name] === 'function') return scopes[i][name].bind(scopes[i]); }
            catch (e) {}
        }
        return null;
    }

    function notify(type, message) {
        var toast = null;
        try { toast = window.toastr || (window.parent && window.parent.toastr) || (window.top && window.top.toastr); } catch (e) {}
        if (toast && typeof toast[type] === 'function') { toast[type](message); return; }
        if (type === 'error' || type === 'warning') alert(message);
    }

    try {
        var getMessages = findApi('getChatMessages');
        var setMessages = findApi('setChatMessages');
        var setSingleMessage = findApi('setChatMessage');

        if (!getMessages || (!setMessages && !setSingleMessage)) {
            notify('error', '找不到 TavernHelper 訊息 API，請確認 TavernHelper 已啟用。');
            return;
        }

        var idx = Number(openingId);
        var messages = await getMessages(0, { include_swipes: true });
        var opening = messages && messages[0];
        var swipes = opening && opening.swipes;

        if (!Array.isArray(swipes) || swipes[idx] === undefined) {
            notify('warning', '找不到場景 ' + openingId);
            return;
        }

        if (setMessages) {
            await setMessages([{ message_id: 0, swipe_id: idx }], { refresh: 'all' });
        } else {
            await setSingleMessage(swipes[idx], 0, { swipe_id: idx, refresh: 'display_and_render_current' });
        }
        notify('success', '已切換至場景 ' + openingId);
    } catch (err) {
        console.error('切換開場白時發生錯誤：', err);
        notify('error', '切換場景失敗，請查看瀏覽器 console。');
    }
};

/* 簡單版：無變數系統，場景切換功能獨立運作 */
</script>
</body>

